"Add-Type -AssemblyName System.Windows.Forms\nAdd-Type -AssemblyName System.Drawing\n\n# Win32 API Definitions\n$code = @\"\nusing System;\nusing System.Runtime.InteropServices;\npublic class Win32 {\n    [DllImport(\"kernel32.dll\")]\n    public static extern IntPtr GetConsoleWindow();\n\n    [DllImport(\"user32.dll\")]\n    public static extern bool ShowWindow(IntPtr hWnd, int nCmdShow);\n\n    [DllImport(\"user32.dll\")]\n    public static extern bool IsWindowVisible(IntPtr hWnd);\n\n    [DllImport(\"shell32.dll\", CharSet = CharSet.Auto)]\n    public static extern IntPtr ExtractIcon(IntPtr hInst, string lpszExeFileName, int nIconIndex);\n}\n\"@\nAdd-Type -TypeDefinition $code\n\n$botDir = Split-Path -Parent $MyInvocation.MyCommand.Path\nSet-Location $botDir\n\n# Set Console Title\n[System.Console]::Title = \"Facebook Bot Console\"\n\n# Start node bot.js --headless (sharing the console)\n$process = Start-Process -FilePath \"node\" -ArgumentList \"bot.js --headless\" -NoNewWindow -PassThru -WorkingDirectory $botDir\n\n# Get Console Window Handle\n$hwnd = [Win32]::GetConsoleWindow()\n\n# Extract a nice icon from shell32.dll (index 13 is globe, perfect for internet/facebook bot)\n$hIcon = [Win32]::ExtractIcon(0, \"shell32.dll\", 13)\nif ($hIcon -ne [IntPtr]::Zero) {\n    $icon = [System.Drawing.Icon]::FromHandle($hIcon)\n} else {\n    $icon = [System.Drawing.SystemIcons]::Information\n}\n\n# Create System Tray Icon\n$trayIcon = New-Object System.Windows.Forms.NotifyIcon\n$trayIcon.Icon = $icon\n$trayIcon.Text = \"Facebook Bot (Running)\"\n$trayIcon.Visible = $true\n\n# Toggle Window Function\nfunction Toggle-ConsoleWindow {\n    $hwnd = [Win32]::GetConsoleWindow()\n    if ($hwnd -ne [IntPtr]::Zero) {\n        if ([Win32]::IsWindowVisible($hwnd)) {\n            [Win32]::ShowWindow($hwnd, 0) | Out-Null # SW_HIDE = 0\n        } else {\n            [Win32]::ShowWindow($hwnd, 5) | Out-Null # SW_SHOW = 5\n        }\n    }\n}\n\n# Double Click action\n$trayIcon.add_DoubleClick({\n    Toggle-ConsoleWindow\n})\n\n# Contex
